import{c as a,Q as e,j as s,m as n}from"./chunks/framework.CQqJojvj.js";const b=JSON.parse('{"title":"08 - 计算机网络","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/08-network.md","filePath":"bagu/08-network.md","lastUpdated":null}'),l={name:"bagu/08-network.md"};function i(r,t,d,p,o,c){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="_08-计算机网络" tabindex="-1">08 - 计算机网络 <a class="header-anchor" href="#_08-计算机网络" aria-label="Permalink to &quot;08 - 计算机网络&quot;">​</a></h1><blockquote><p>网络是分布式系统的基石。HTTP/HTTPS、TCP/UDP、DNS 是面试中最常问的网络知识点。</p></blockquote><hr><h2 id="_1-http-https" tabindex="-1">1. HTTP &amp; HTTPS <a class="header-anchor" href="#_1-http-https" aria-label="Permalink to &quot;1. HTTP &amp; HTTPS&quot;">​</a></h2><h3 id="http-各版本演进" tabindex="-1">HTTP 各版本演进 <a class="header-anchor" href="#http-各版本演进" aria-label="Permalink to &quot;HTTP 各版本演进&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">版本</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;">HTTP/1.0</td><td style="text-align:left;">短连接，每次请求建立 TCP 连接</td></tr><tr><td style="text-align:left;">HTTP/1.1</td><td style="text-align:left;">持久连接（Keep-Alive）、管道化、Host 头、断点续传</td></tr><tr><td style="text-align:left;">HTTP/2.0</td><td style="text-align:left;">多路复用、头部压缩（HPACK）、服务器推送、二进制分帧</td></tr><tr><td style="text-align:left;">HTTP/3.0</td><td style="text-align:left;">基于 QUIC（UDP）、0-RTT 握手、无队头阻塞</td></tr></tbody></table><h3 id="https-握手流程" tabindex="-1">HTTPS 握手流程 <a class="header-anchor" href="#https-握手流程" aria-label="Permalink to &quot;HTTPS 握手流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 客户端 → 服务器: ClientHello（支持的 TLS 版本 + 加密套件 + 随机数1）</span></span>
<span class="line"><span>2. 服务器 → 客户端: ServerHello（选定的加密套件 + 随机数2）+ 证书</span></span>
<span class="line"><span>3. 客户端验证证书（CA 签名 + 域名）</span></span>
<span class="line"><span>4. 客户端生成 Pre-Master Secret，用服务器公钥加密发送</span></span>
<span class="line"><span>5. 双方用 随机数1 + 随机数2 + Pre-Master Secret 生成会话密钥</span></span>
<span class="line"><span>6. 后续通信使用对称密钥加密</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="http-状态码" tabindex="-1">HTTP 状态码 <a class="header-anchor" href="#http-状态码" aria-label="Permalink to &quot;HTTP 状态码&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">范围</th><th style="text-align:left;">含义</th><th style="text-align:left;">常见状态码</th></tr></thead><tbody><tr><td style="text-align:left;">1xx</td><td style="text-align:left;">信息</td><td style="text-align:left;">101 Switching Protocols（WebSocket 升级）</td></tr><tr><td style="text-align:left;">2xx</td><td style="text-align:left;">成功</td><td style="text-align:left;">200 OK, 201 Created, 204 No Content</td></tr><tr><td style="text-align:left;">3xx</td><td style="text-align:left;">重定向</td><td style="text-align:left;">301 永久重定向, 302 临时重定向, 304 Not Modified</td></tr><tr><td style="text-align:left;">4xx</td><td style="text-align:left;">客户端错误</td><td style="text-align:left;">400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found, 429 Too Many Requests</td></tr><tr><td style="text-align:left;">5xx</td><td style="text-align:left;">服务器错误</td><td style="text-align:left;">500 Internal Server Error, 502 Bad Gateway, 503 Service Unavailable, 504 Gateway Timeout</td></tr></tbody></table><h3 id="get-vs-post" tabindex="-1">GET vs POST <a class="header-anchor" href="#get-vs-post" aria-label="Permalink to &quot;GET vs POST&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">GET</th><th style="text-align:left;">POST</th></tr></thead><tbody><tr><td style="text-align:left;">语义</td><td style="text-align:left;">获取资源</td><td style="text-align:left;">创建/修改资源</td></tr><tr><td style="text-align:left;">参数位置</td><td style="text-align:left;">URL 查询字符串</td><td style="text-align:left;">请求体</td></tr><tr><td style="text-align:left;">缓存</td><td style="text-align:left;">可缓存</td><td style="text-align:left;">不可缓存（默认）</td></tr><tr><td style="text-align:left;">幂等</td><td style="text-align:left;">是</td><td style="text-align:left;">否</td></tr><tr><td style="text-align:left;">安全性</td><td style="text-align:left;">参数暴露在 URL</td><td style="text-align:left;">参数在请求体（相对安全）</td></tr><tr><td style="text-align:left;">长度限制</td><td style="text-align:left;">受 URL 长度限制（浏览器/服务器限制）</td><td style="text-align:left;">无明确限制</td></tr></tbody></table><hr><h2 id="_2-tcp" tabindex="-1">2. TCP <a class="header-anchor" href="#_2-tcp" aria-label="Permalink to &quot;2. TCP&quot;">​</a></h2><h3 id="tcp-三次握手" tabindex="-1">TCP 三次握手 <a class="header-anchor" href="#tcp-三次握手" aria-label="Permalink to &quot;TCP 三次握手&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端                        服务器</span></span>
<span class="line"><span>  │ ------ SYN (seq=x) --------→ │  第一次：客户端发 SYN</span></span>
<span class="line"><span>  │ ←-- SYN+ACK (seq=y, ack=x+1) │  第二次：服务器回 SYN+ACK</span></span>
<span class="line"><span>  │ ------ ACK (ack=y+1) ------→ │  第三次：客户端确认</span></span>
<span class="line"><span>  │        连接建立               │</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>为什么是三次而不是两次？</strong></p><p>防止已失效的连接请求到达服务器后，服务器误以为新连接。如果只有两次握手，服务器收到迟到的 SYN 会直接建立连接，浪费资源。</p><h3 id="tcp-四次挥手" tabindex="-1">TCP 四次挥手 <a class="header-anchor" href="#tcp-四次挥手" aria-label="Permalink to &quot;TCP 四次挥手&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端                        服务器</span></span>
<span class="line"><span>  │ ------ FIN (seq=u) --------→ │  第一次：客户端发 FIN</span></span>
<span class="line"><span>  │ ←-- ACK (ack=u+1) ----------│  第二次：服务器确认</span></span>
<span class="line"><span>  │ ←-- FIN (seq=v, ack=u+1) ---│  第三次：服务器发 FIN</span></span>
<span class="line"><span>  │ ------ ACK (ack=v+1) ------→ │  第四次：客户端确认</span></span>
<span class="line"><span>  │  等待 2MSL 后关闭               │</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>为什么是四次？</strong></p><p>TCP 是全双工的，每个方向需要单独关闭。服务器收到 FIN 后可能还有数据要发送，所以 ACK 和 FIN 分开发送。</p><p><strong>为什么需要 TIME_WAIT（2MSL）？</strong></p><ol><li>确保最后的 ACK 能被服务器收到（如果 ACK 丢失，服务器会重发 FIN）</li><li>让旧连接的报文在网络中消失，避免影响新连接</li></ol><h3 id="tcp-可靠性保证" tabindex="-1">TCP 可靠性保证 <a class="header-anchor" href="#tcp-可靠性保证" aria-label="Permalink to &quot;TCP 可靠性保证&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">机制</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>序列号 + 确认应答</strong></td><td style="text-align:left;">每个字节编号，接收方确认已收到的字节</td></tr><tr><td style="text-align:left;"><strong>超时重传</strong></td><td style="text-align:left;">超过 RTO（重传超时时间）未收到 ACK，重发数据</td></tr><tr><td style="text-align:left;"><strong>流量控制</strong></td><td style="text-align:left;">滑动窗口，接收方告知剩余缓冲区大小</td></tr><tr><td style="text-align:left;"><strong>拥塞控制</strong></td><td style="text-align:left;">慢启动 → 拥塞避免 → 快速重传 → 快速恢复</td></tr><tr><td style="text-align:left;"><strong>校验和</strong></td><td style="text-align:left;">检测数据在传输中的错误</td></tr></tbody></table><h3 id="tcp-粘包和拆包" tabindex="-1">TCP 粘包和拆包 <a class="header-anchor" href="#tcp-粘包和拆包" aria-label="Permalink to &quot;TCP 粘包和拆包&quot;">​</a></h3><ul><li><strong>粘包：</strong> 多个小包被合并为一个（Nagle 算法导致）</li><li><strong>拆包：</strong> 大包被拆分为多个 TCP 段（MSS 限制）</li></ul><p><strong>解决方式：</strong></p><ol><li>固定长度消息（适用于固定长度协议）</li><li>分隔符（如 <code>\\r\\n</code>，HTTP 使用）</li><li>消息头 + 消息体（消息头包含 body 长度）</li></ol><hr><h2 id="_3-键入网址到网页显示-期间发生了什么" tabindex="-1">3. 键入网址到网页显示，期间发生了什么？ <a class="header-anchor" href="#_3-键入网址到网页显示-期间发生了什么" aria-label="Permalink to &quot;3. 键入网址到网页显示，期间发生了什么？&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. URL 解析 — 提取协议、域名、路径</span></span>
<span class="line"><span>2. DNS 解析 — 域名 → IP 地址（浏览器缓存 → hosts → DNS 服务器 递归/迭代查询）</span></span>
<span class="line"><span>3. TCP 连接 — 三次握手建立连接（HTTPS 再进行 TLS 握手）</span></span>
<span class="line"><span>4. 发送 HTTP 请求 — 构建请求报文并发送</span></span>
<span class="line"><span>5. 服务器处理 — 接收请求并返回响应</span></span>
<span class="line"><span>6. 浏览器解析渲染 — HTML → DOM Tree, CSS → CSSOM → Render Tree → Layout → Paint</span></span>
<span class="line"><span>7. TCP 断开 — 四次挥手（Connection: keep-alive 则保持连接）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="_4-cdn" tabindex="-1">4. CDN <a class="header-anchor" href="#_4-cdn" aria-label="Permalink to &quot;4. CDN&quot;">​</a></h2><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户 → 就近 CDN 边缘节点 → 缓存命中返回 → 未命中回源（源站）→ 缓存并返回</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h3><ol><li><strong>DNS 智能解析</strong> — 根据用户 IP 返回最近的 CDN 节点 IP</li><li><strong>内容缓存</strong> — 静态资源缓存在边缘节点</li><li><strong>缓存更新</strong> — 通过 URL 版本号 / hash / CDN 刷新接口</li></ol><h3 id="cdn-对业务的作用" tabindex="-1">CDN 对业务的作用 <a class="header-anchor" href="#cdn-对业务的作用" aria-label="Permalink to &quot;CDN 对业务的作用&quot;">​</a></h3><ul><li>加速静态资源（JS/CSS/图片）</li><li>减少源站带宽压力</li><li>防御部分 DDoS 攻击</li></ul>`,41)])])}const g=a(l,[["render",i]]);export{b as __pageData,g as default};
